1	import { NextResponse } from "next/server";
2	import { createClient } from "@/lib/supabase/server";
3	import { buildBackendFindingsSnapshot } from "@/lib/server/backend-findings";
4	import { createIssue, loadIssue } from "@/lib/server/issue-store";
5	import { seedIssueFromOrigin } from "@/lib/server/issue-agent";
6	import { drainIssueQueue, queueIssueRun, shouldInlineDrain } from "@/lib/server/issue-workflow";
7	import { loadIssueViewState } from "@/lib/server/issue-view";
8	
9	export const runtime = "nodejs";
10	export const dynamic = "force-dynamic";
11	export const maxDuration = 120;
12	
13	export async function POST(request: Request) {
14	  try {
15	    const supabase = await createClient();
16	    const { data: { user } } = await supabase.auth.getUser();
17	    if (!user) return NextResponse.json({ error: "Authentication required." }, { status: 401 });
18	
19	    const body = await request.json() as {
20	      originType: "manual" | "alert" | "problem";
21	      originId?: string;
22	      title?: string;
23	      description?: string;
24	      importCurrentFindings?: boolean;
25	    };
26	
27	    let title = body.title?.trim() ?? "";
28	    let seed = body.description?.trim() ?? "";
29	    let severity: "critical" | "warning" | "info" = "warning";
30	    let affectedNas: string[] = [];
31	    let metadata: Record<string, unknown> = {};
32	
33	    if (body.importCurrentFindings) {
34	      const snapshot = await buildBackendFindingsSnapshot(supabase);
35	      title = snapshot.title;
36	      seed = snapshot.seed;
37	      severity = snapshot.severity;
38	      affectedNas = snapshot.affectedNas;
39	      metadata = snapshot.metadata;
40	    }
41	
42	    if (body.originType === "problem" && body.originId) {
43	      // originId is now an issue ID from /api/analysis (which creates issues
44	      // via runIssueDetection, not analyzed_problems).
45	      const { data: sourceIssue } = await supabase
46	        .from("issues")
47	        .select("title, summary, current_hypothesis, severity, affected_nas")
48	        .eq("id", body.originId)
49	        .maybeSingle();
50	
51	      if (sourceIssue) {
52	        title = title || sourceIssue.title;
53	        const hypothesis = sourceIssue.current_hypothesis ? `\n\nHypothesis: ${sourceIssue.current_hypothesis}` : "";
54	        seed = seed || `${sourceIssue.summary || sourceIssue.title}${hypothesis}`;
55	        severity = sourceIssue.severity ?? severity;
56	        affectedNas = (sourceIssue.affected_nas as string[]) ?? [];
57	      }
58	    }
59	
60	    if (body.originType === "alert" && body.originId) {
61	      const { data: alert } = await supabase
62	        .from("alerts")
